import{_ as e,o as s,c as t,ag as r}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"日本JR Pass","description":"日本铁路通票购买和使用完整攻略","frontmatter":{"title":"日本JR Pass","description":"日本铁路通票购买和使用完整攻略"},"headers":[],"relativePath":"knowledge/transportation/jrpass.md","filePath":"knowledge/transportation/jrpass.md","lastUpdated":null}'),o={name:"knowledge/transportation/jrpass.md"};function n(i,a,l,d,p,h){return s(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="日本jr-pass" tabindex="-1">日本JR Pass <a class="header-anchor" href="#日本jr-pass" aria-label="Permalink to &quot;日本JR Pass&quot;">​</a></h1><h2 id="jr-pass类型" tabindex="-1">JR Pass类型 <a class="header-anchor" href="#jr-pass类型" aria-label="Permalink to &quot;JR Pass类型&quot;">​</a></h2><p>JR Pass分为7天、14天和21天三种有效期。还有地区性通票如关西广域通票和北海道通票。</p><h2 id="购买方式" tabindex="-1">购买方式 <a class="header-anchor" href="#购买方式" aria-label="Permalink to &quot;购买方式&quot;">​</a></h2><p>JR Pass必须在入境日本前通过海外指定代理商购买换取券，入境后在JR车站兑换正式通票。</p><h2 id="使用范围" tabindex="-1">使用范围 <a class="header-anchor" href="#使用范围" aria-label="Permalink to &quot;使用范围&quot;">​</a></h2><p>JR Pass覆盖JR集团旗下的新干线（除希望号、瑞穗号）、特急列车和普通列车。私铁和地铁需另外购票。</p><h2 id="激活与使用" tabindex="-1">激活与使用 <a class="header-anchor" href="#激活与使用" aria-label="Permalink to &quot;激活与使用&quot;">​</a></h2><p>兑换时指定启用日期。进出站需走人工通道或持有通票的自动闸机，不能通过普通闸机。</p><h2 id="划算程度分析" tabindex="-1">划算程度分析 <a class="header-anchor" href="#划算程度分析" aria-label="Permalink to &quot;划算程度分析&quot;">​</a></h2><p>东京-大阪往返一次即可回本。行程中包含多个远程城市间的移动时，JR Pass的性价比极高。</p>',11)])])}const P=e(o,[["render",n]]);export{_ as __pageData,P as default};
